import { request } from '../axios';

// Previous version - Stopped working 31/01/23 between 5:20 pm and 8:00 pm
export async function _validateToken(stateToken: string, oktaEnv: string) {
  const introspectUrl = `https://${oktaEnv}/api/v1/authn/introspect`;
  return request({ method: 'POST', url: introspectUrl, data: { stateToken } });
}

export async function validateToken(stateToken: string, oktaEnv: string) {
  const introspectUrl = `https://${oktaEnv}/idp/idx/introspect`;
  return request({ method: 'POST', url: introspectUrl, data: { stateToken } });
}
